 1→import useSWR from "swr";
 2→import type { RepoWithCheckpoints } from "@/types/checkpoint";
 3→
 4→const fetcher = async (url: string) => {
 5→  const res = await fetch(url);
 6→  if (!res.ok) throw new Error(`${res.status}`);
 7→  return res.json();
 8→};
 9→
10→export function useRepos() {
11→  const { data, error, isLoading } = useSWR<RepoWithCheckpoints[]>(
12→    "/api/github/repos",
13→    fetcher
14→  );
15→
16→  return {
17→    repos: data,
18→    isLoading,
19→    isError: !!error,
20→  };
21→}
