 1→import { Octokit } from "@octokit/rest";
 2→import type { RepoWithCheckpoints } from "@/types/checkpoint";
 3→
 4→const CHECKPOINT_BRANCH = "partio/checkpoints/v1";
 5→
 6→export async function listReposWithCheckpoints(
 7→  octokit: Octokit
 8→): Promise<RepoWithCheckpoints[]> {
 9→  const { data: repos } = await octokit.repos.listForAuthenticatedUser({
10→    sort: "updated",
11→    per_page: 100,
12→    visibility: "all",
13→  });
14→
15→  const results = await Promise.allSettled(
16→    repos.map(async (repo) => {
17→      let checkpointCount = 0;
18→      try {
19→        const { data: ref } = await octokit.git.getRef({
20→          owner: repo.owner.login,
21→          repo: repo.name,
22→          ref: `heads/${CHECKPOINT_BRANCH}`,
23→        });
24→
25→        const { data: commit } = await octokit.git.getCommit({
26→          owner: repo.owner.login,
27→          repo: repo.name,
28→          commit_sha: ref.object.sha,
29→        });
30→
31→        const { data: tree } = await octokit.git.getTree({
32→          owner: repo.owner.login,
33→          repo: repo.name,
34→          tree_sha: commit.tree.sha,
35→          recursive: "1",
36→        });
37→
38→        checkpointCount = (tree.tree || []).filter(
39→          (entry) =>
40→            entry.path &&
41→            /^[0-9a-f]{2}\/[0-9a-f]{10}\/metadata\.json$/.test(entry.path)
42→        ).length;
43→      } catch {
44→        // No checkpoint branch — that's fine
45→      }
46→
47→      return {
48→        owner: repo.owner.login,
49→        name: repo.name,
50→        full_name: repo.full_name,
51→        language: repo.language ?? null,
52→        stars: repo.stargazers_count ?? 0,
53→        checkpoint_count: checkpointCount,
54→        updated_at: repo.updated_at ?? new Date().toISOString(),
55→        description: repo.description ?? null,
56→        open_issues_count: repo.open_issues_count ?? 0,
57→      } satisfies RepoWithCheckpoints;
58→    })
59→  );
60→
61→  return results
62→    .filter(
63→      (r): r is PromiseFulfilledResult<RepoWithCheckpoints> =>
64→        r.status === "fulfilled"
65→    )
66→    .map((r) => r.value);
67→}
