 18→function countDiffFiles(diff: string | undefined): number {
 19→  if (!diff) return 0;
 20→  return (diff.match(/^diff --git/gm) || []).length;
 21→}
 22→
 23→function extractToolCount(messages: { content: string }[]): number {
 24→  const tools = new Set<string>();
 25→  for (const msg of messages) {
 26→    const matches = msg.content.match(/\[Tool: (.+?)\]/g);
 27→    if (matches) {
 28→      for (const m of matches) {
 29→        tools.add(m.replace("[Tool: ", "").replace("]", ""));
 30→      }
 31→    }
 32→  }
 33→  return tools.size;
 34→}
