### 6. GitHub Library (lib/github/)

#### **repos.ts - listReposWithCheckpoints()**
```typescript
const CHECKPOINT_BRANCH = "partio/checkpoints/v1";

export async function listReposWithCheckpoints(octokit: Octokit): Promise<RepoWithCheckpoints[]> {
  // 1. Get all user repos
  const { data: repos } = await octokit.repos.listForAuthenticatedUser({
    sort: "updated",
    per_page: 100,
    visibility: "all",
  });

  // 2. For each repo, try to get checkpoint count from the checkpoint branch
  const results = await Promise.allSettled(
    repos.map(async (repo) => {
      let checkpointCount = 0;
      try {
        const { data: ref } = await octokit.git.getRef({
          owner: repo.owner.login,
          repo: repo.name,
          ref: `heads/${CHECKPOINT_BRANCH}`,
        });

        // Navigate: ref -> commit -> tree
        const { data: commit } = await octokit.git.getCommit({
          owner: repo.owner.login,
          repo: repo.name,
          commit_sha: ref.object.sha,
        });

        const { data: tree } = await octokit.git.getTree({
          owner: repo.owner.login,
          repo: repo.name,
          tree_sha: commit.tree.sha,
          recursive: "1",
        });

        // Count files matching pattern: XX/YYYYYYYYYY/metadata.json
        checkpointCount = (tree.tree || []).filter(
          (entry) =>
            entry.path &&
            /^[0-9a-f]{2}\/[0-9a-f]{10}\/metadata\.json$/.test(entry.path)
        ).length;
      } catch {
        // No checkpoint branch = 0 checkpoints
      }

      return {
        owner: repo.owner.login,
        name: repo.name,
        full_name: repo.full_name,
        language: repo.language ?? null,
        stars: repo.stargazers_count ?? 0,
        checkpoint_count: checkpointCount,
        updated_at: repo.updated_at ?? new Date().toISOString(),
        description: repo.description ?? null,
        open_issues_count: repo.open_issues_count ?? 0,
      } satisfies RepoWithCheckpoints;
    })
  );

  // Return only fulfilled promises
  return results
    .filter((r): r is PromiseFulfilledResult<RepoWithCheckpoints> => r.status === "fulfilled")
    .map((r) => r.value);
}
```

#### **checkpoints.ts**
```typescript
export async function listCheckpoints(
  octokit: Octokit,
  owner: string,
  repo: string
): Promise<CheckpointMetadata[]> {
  // Navigate to checkpoint branch and get all metadata.json files
  const { data: ref } = await octokit.git.getRef({
    owner,
    repo,
    ref: `heads/${CHECKPOINT_BRANCH}`,
  });

  const { data: commit } = await octokit.git.getCommit({
    owner,
    repo,
    commit_sha: ref.object.sha,
  });

  const { data: tree } = await octokit.git.getTree({
    owner,
    repo,
    tree_sha: commit.tree.sha,
    recursive: "1",
  });

  // Filter metadata files and fetch each blob
  const metadataEntries = (tree.tree || []).filter(
    (entry) =>
      entry.path &&
      /^[0-9a-f]{2}\/[0-9a-f]{10}\/metadata\.json$/.test(entry.path)
  );

  const checkpoints = await Promise.allSettled(
    metadataEntries.map(async (entry) => {
      const { data: blob } = await octokit.git.getBlob({
        owner,
        repo,
        file_sha: entry.sha!,
      });

      const content = Buffer.from(blob.content, "base64").toString("utf-8");
      return JSON.parse(content) as CheckpointMetadata;
    })
  );

  // Return sorted by created_at descending
  return checkpoints
    .filter((r): r is PromiseFulfilledResult<CheckpointMetadata> => r.status === "fulfilled")
    .map((r) => r.value)
    .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
}

export async function getCheckpoint(
  octokit: Octokit,
  owner: string,
  repo: string,
  checkpointId: string
): Promise<CheckpointMetadata | null> {
  // Extract shard (first 2 hex chars) and rest
  const shard = checkpointId.slice(0, 2);
  const rest = checkpointId.slice(2);

  try {
    // Navigate to checkpoint branch, get tree, find metadata file
    const { data: ref } = await octokit.git.getRef({
      owner,
      repo,
      ref: `heads/${CHECKPOINT_BRANCH}`,
    });

    const { data: commit } = await octokit.git.getCommit({
      owner,
      repo,
      commit_sha: ref.object.sha,
    });

    const { data: tree } = await octokit.git.getTree({
      owner,
      repo,
      tree_sha: commit.tree.sha,
      recursive: "1",
    });

    const metadataPath = `${shard}/${rest}/metadata.json`;
    const entry = (tree.tree || []).find((e) => e.path === metadataPath);

    if (!entry?.sha) return null;

    const { data: blob } = await octokit.git.getBlob({
      owner,
      repo,
      file_sha: entry.sha,
    });

    const content = Buffer.from(blob.content, "base64").toString("utf-8");
    return JSON.parse(content) as CheckpointMetadata;
  } catch {
    return null;
  }
}
```

#### **session.ts - getSessionData()**
```typescript
export async function getSessionData(
  octokit: Octokit,
  owner: string,
  repo: string,
  checkpointId: string
): Promise<Message[]> {
  const shard = checkpointId.slice(0, 2);
  const rest = checkpointId.slice(2);

  try {
    // Navigate to checkpoint branch, find full.jsonl file
    const { data: ref } = await octokit.git.getRef({
      owner,
      repo,
      ref: `heads/${CHECKPOINT_BRANCH}`,
    });

    const { data: commit } = await octokit.git.getCommit({
      owner,
      repo,
      commit_sha: ref.object.sha,
    });

    const { data: tree } = await octokit.git.getTree({
      owner,
      repo,
      tree_sha: commit.tree.sha,
      recursive: "1",
    });

    const sessionPath = `${shard}/${rest}/0/full.jsonl`;
    const entry = (tree.tree || []).find((e) => e.path === sessionPath);

    if (!entry?.sha) return [];

    const { data: blob } = await octokit.git.getBlob({
      owner,
      repo,
      file_sha: entry.sha,
    });

    const content = Buffer.from(blob.content, "base64").toString("utf-8");
    const lines = content.split("\n").filter((line) => line.trim());

    const MESSAGE_TYPES = new Set(["user", "human", "assistant"]);

    return lines
      .map((line) => JSON.parse(line))
      .filter((parsed: any) => MESSAGE_TYPES.has(parsed.type || parsed.role))
      .map((parsed: any) => ({
        role: parsed.type || parsed.role || "unknown",
        content: stripSystemTags(extractText(parsed)),
        timestamp: parsed.timestamp || "",
        tokens: parsed.tokens,
      }))
      .filter((msg) => msg.content.trim() !== "");
  } catch {
    return [];
  }
}

// Helper: extractText() - handles multiple message formats
function extractText(entry: Record<string, unknown>): string {
  // 1. Try contentBlocks (array of {type, text})
  if (Array.isArray(entry.contentBlocks)) {
    return extractContentBlocks(entry.contentBlocks);
  }

  // 2. Try message field
  if (entry.message != null) {
    if (typeof entry.message === "string") return entry.message;
    const msg = entry.message as any;
    if (typeof msg.content === "string") return msg.content;
    if (Array.isArray(msg.content)) {
      return extractContentBlocks(msg.content);
    }
  }

  // 3. Try content field
  if (entry.content != null) {
    if (typeof entry.content === "string") return entry.content;
    if (Array.isArray(entry.content)) {
      return extractContentBlocks(entry.content as any[]);
    }
  }

  return "";
}

// Strips [Tool: X], [Tool Result: X], and system tags
function stripSystemTags(text: string): string {
  const SYSTEM_TAG_RE = /<(local-command-caveat|command-name|command-message|command-args|local-command-stdout|system-reminder|user-prompt-submit-hook)>[\s\S]*?<\/\1>/g;
  return text.replace(SYSTEM_TAG_RE, "");
}

function extractContentBlocks(blocks: any[]): string {
  return blocks
    .map((block: any) => {
      if (typeof block === "string") return block;
      if (block?.type === "text") return block.text || "";
      if (block?.type === "tool_use") return `[Tool: ${block.name || "unknown"}]`;
      if (block?.type === "tool_result") return `[Tool Result: ${typeof block.content === "string" ? block.content.slice(0, 200) : "..."}]`;
      return "";
    })
    .filter(Boolean)
    .join("\n");
}
```

#### **diff.ts - getCheckpointDiff()**
```typescript
export async function getCheckpointDiff(
  octokit: Octokit,
  owner: string,
  repo: string,
  checkpointId: string
): Promise<string> {
  const shard = checkpointId.slice(0, 2);
  const rest = checkpointId.slice(2);

  try {
    // Find and read 0/diff.patch file
    const { data: ref } = await octokit.git.getRef({
      owner,
      repo,
      ref: `heads/${CHECKPOINT_BRANCH}`,
    });

    const { data: commit } = await octokit.git.getCommit({
      owner,
      repo,
      commit_sha: ref.object.sha,
    });

    const { data: tree } = await octokit.git.getTree({
      owner,
      repo,
      tree_sha: commit.tree.sha,
      recursive: "1",
    });

    const diffPath = `${shard}/${rest}/0/diff.patch`;
    const entry = (tree.tree || []).find((e) => e.path === diffPath);

    if (!entry?.sha) return "";

    const { data: blob } = await octokit.git.getBlob({
      owner,
      repo,
      file_sha: entry.sha,
    });

    return Buffer.from(blob.content, "base64").toString("utf-8");
  } catch {
    return "";
  }
}
```

