export async function getSessionData(
  octokit: Octokit,
  owner: string,
  repo: string,
  checkpointId: string
): Promise<Message[]> {
  const shard = checkpointId.slice(0, 2);
  const rest = checkpointId.slice(2);

  try {
    // Navigate to checkpoint branch, find full.jsonl file
    const { data: ref } = await octokit.git.getRef({
      owner,
      repo,
      ref: `heads/${CHECKPOINT_BRANCH}`,
    });

    const { data: commit } = await octokit.git.getCommit({
      owner,
      repo,
      commit_sha: ref.object.sha,
    });

    const { data: tree } = await octokit.git.getTree({
      owner,
      repo,
      tree_sha: commit.tree.sha,
      recursive: "1",
    });

    const sessionPath = `${shard}/${rest}/0/full.jsonl`;
    const entry = (tree.tree || []).find((e) => e.path === sessionPath);

    if (!entry?.sha) return [];

    const { data: blob } = await octokit.git.getBlob({
      owner,
      repo,
      file_sha: entry.sha,
    });

    const content = Buffer.from(blob.content, "base64").toString("utf-8");
    const lines = content.split("\n").filter((line) => line.trim());

    const MESSAGE_TYPES = new Set(["user", "human", "assistant"]);

    return lines
      .map((line) => JSON.parse(line))
      .filter((parsed: any) => MESSAGE_TYPES.has(parsed.type || parsed.role))
      .map((parsed: any) => ({
        role: parsed.type || parsed.role || "unknown",
        content: stripSystemTags(extractText(parsed)),
        timestamp: parsed.timestamp || "",
        tokens: parsed.tokens,
      }))
      .filter((msg) => msg.content.trim() !== "");
  } catch {
    return [];
  }
}

// Helper: extractText() - handles multiple message formats
function extractText(entry: Record<string, unknown>): string {
  // 1. Try contentBlocks (array of {type, text})
  if (Array.isArray(entry.contentBlocks)) {
    return extractContentBlocks(entry.contentBlocks);
  }

  // 2. Try message field
  if (entry.message != null) {
    if (typeof entry.message === "string") return entry.message;
    const msg = entry.message as any;
    if (typeof msg.content === "string") return msg.content;
    if (Array.isArray(msg.content)) {
      return extractContentBlocks(msg.content);
    }
  }

  // 3. Try content field
  if (entry.content != null) {
    if (typeof entry.content === "string") return entry.content;
    if (Array.isArray(entry.content)) {
      return extractContentBlocks(entry.content as any[]);
    }
  }

  return "";
}

// Strips [Tool: X], [Tool Result: X], and system tags
function stripSystemTags(text: string): string {
  const SYSTEM_TAG_RE = /<(local-command-caveat|command-name|command-message|command-args|local-command-stdout|system-reminder|user-prompt-submit-hook)>[\s\S]*?<\/\1>/g;
  return text.replace(SYSTEM_TAG_RE, "");
}

function extractContentBlocks(blocks: any[]): string {
  return blocks
    .map((block: any) => {
      if (typeof block === "string") return block;
      if (block?.type === "text") return block.text || "";
      if (block?.type === "tool_use") return `[Tool: ${block.name || "unknown"}]`;
      if (block?.type === "tool_result") return `[Tool Result: ${typeof block.content === "string" ? block.content.slice(0, 200) : "..."}]`;
      return "";
    })
    .filter(Boolean)
    .join("\n");
}
```

#### **diff.ts - getCheckpointDiff()**
```typescript
export async function getCheckpointDiff(
  octokit: Octokit,
  owner: string,
  repo: string,
  checkpointId: string
): Promise<string> {
  const shard = checkpointId.slice(0, 2);
  const rest = checkpointId.slice(2);

  try {
    // Find and read 0/diff.patch file
    const { data: ref } = await octokit.git.getRef({
      owner,
      repo,
      ref: `heads/${CHECKPOINT_BRANCH}`,
    });

    const { data: commit } = await octokit.git.getCommit({
      owner,
      repo,
      commit_sha: ref.object.sha,
    });

    const { data: tree } = await octokit.git.getTree({
      owner,
      repo,
      tree_sha: commit.tree.sha,
      recursive: "1",
    });

    const diffPath = `${shard}/${rest}/0/diff.patch`;
    const entry = (tree.tree || []).find((e) => e.path === diffPath);

    if (!entry?.sha) return "";

    const { data: blob } = await octokit.git.getBlob({
      owner,
      repo,
      file_sha: entry.sha,
    });

    return Buffer.from(blob.content, "base64").toString("utf-8");
  } catch {
    return "";
  }
}
```

---

### 7. API Routes Pattern

All API routes follow this pattern:
```typescript
import { NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { createOctokit } from "@/lib/github";

export async function GET(
  _request: Request,
  { params }: { params: Promise<{ owner: string; repo: string; id?: string }> }
) {
  // 1. Authenticate
  const session = await auth();
  if (!session?.accessToken) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  // 2. Await params (Next.js 15 pattern)
  const { owner, repo, id } = await params;

  // 3. Create Octokit client
  const octokit = createOctokit(session.accessToken);

  // 4. Call GitHub lib
  const data = await someGithubFunction(octokit, owner, repo, id);

  // 5. Return JSON
  return NextResponse.json(data);
}
```

---

### 8. Page Components Pattern

#### **[owner]/[repo]/page.tsx**
```typescript
"use client";

import { use } from "react";
import { useCheckpoints } from "@/hooks/use-checkpoints";

export default function RepoDetailPage({
  params,
}: {
  params: Promise<{ owner: string; repo: string }>;
}) {
  const { owner, repo } = use(params);  // Unwrap params promise
  const { checkpoints, isLoading } = useCheckpoints(owner, repo);

  if (isLoading) return <Skeleton />;

  return (
    <div>
      {checkpoints?.map(cp => (
        <Link key={cp.id} href={`/${owner}/${repo}/${cp.id}`}>
          {/* Render checkpoint item */}
        </Link>
      ))}
    </div>
  );
}
```

#### **[owner]/[repo]/[checkpointId]/page.tsx**
```typescript
"use client";

import { use, useState, useMemo } from "react";
import {
  useCheckpoint,
  useSession as useCheckpointSession,
  useDiff,
} from "@/hooks/use-checkpoints";

type Tab = "sessions" | "files";

export default function CheckpointDetailPage({
  params,
}: {
  params: Promise<{ owner: string; repo: string; checkpointId: string }>;
}) {
  const { owner, repo, checkpointId } = use(params);
  const { checkpoint, isLoading: cpLoading } = useCheckpoint(owner, repo, checkpointId);
  const { messages, isLoading: sessionLoading } = useCheckpointSession(owner, repo, checkpointId);
  const { diff, isLoading: diffLoading } = useDiff(owner, repo, checkpointId);

  const [activeTab, setActiveTab] = useState<Tab>("sessions");

  // Compute stats
  const pageTitle = useMemo(() => {
    const firstHuman = messages?.find(m => m.role === "human" || m.role === "user");
    return firstHuman?.content.slice(0, 100) + "...";
  }, [messages]);

  const totalTokens = useMemo(() => {
    return messages?.reduce((sum, m) => sum + (m.tokens || 0), 0) ?? 0;
  }, [messages]);

  const fileCount = useMemo(() => {
    return (diff?.match(/^diff --git/gm) || []).length;
  }, [diff]);

  return (
    <div>
      {/* Header with stats */}
      <h1>{pageTitle}</h1>

      {/* Tabs */}
      <button onClick={() => setActiveTab("sessions")}>Sessions</button>
      <button onClick={() => setActiveTab("files")}>Files ({fileCount})</button>

      {/* Tab content */}
      {activeTab === "sessions" && (
        sessionLoading ? <Skeleton /> : <TranscriptViewer messages={messages || []} />
      )}

      {activeTab === "files" && (
        diffLoading ? <Skeleton /> : <DiffViewer diff={diff || ""} />
      )}
    </div>
  );
}
```

