### 10. Middleware & Auth

#### **middleware.ts**
```typescript
export default auth((req) => {
  const isLoggedIn = !!req.auth?.user;
  const isOnLogin = req.nextUrl.pathname.startsWith("/login");

  if (!isLoggedIn && !isOnLogin) {
    return NextResponse.redirect(new URL("/login", req.url));
  }

  if (isLoggedIn && isOnLogin) {
    return NextResponse.redirect(new URL("/", req.url));
  }

  return NextResponse.next();
});

export const config = {
  matcher: ["/((?!api/auth|_next/static|_next/image|favicon.ico|partio-logo.svg).*)"],
};
```

#### **auth.ts (NextAuth Config)**
```typescript
export const { handlers, auth, signIn, signOut } = NextAuth({
  providers: [
    GitHub({
      clientId: process.env.GITHUB_CLIENT_ID,
      clientSecret: process.env.GITHUB_CLIENT_SECRET,
      authorization: {
        params: {
          scope: "repo read:user",  // Permissions
        },
      },
    }),
  ],
  callbacks: {
    async jwt({ token, account, profile }) {
      if (account) {
        token.accessToken = account.access_token;  // Store token in JWT
      }
      if (profile) {
        token.login = (profile as { login?: string }).login;
      }
      return token;
    },
    async session({ session, token }) {
      session.accessToken = token.accessToken as string | undefined;
      if (token.login) {
        session.user.login = token.login as string;
      }
      return session;
    },
  },
  pages: {
    signIn: "/login",
  },
});
```

---

### 11. Component Patterns

#### **TranscriptViewer** (transcript-viewer.tsx)
- Displays Session Accordion with collapsible messages
- Parses `[Tool: X]` syntax from content
- Shows attribution bar (AI percent)
- Avatar for human vs assistant
- Stats: prompt, steps, tool count, tokens, duration, start time
- Expandable messages with collapse threshold

#### **DiffViewer** (diff-viewer.tsx)
- Parses unified diff format
- Groups by file (diff --git header)
- Collapsible file blocks
- Line coloring: green (+), red (-), context
- Shows additions/deletions count

#### **DataTable** (data-table.tsx)
- Generic table with columns
- Column interface: `{ key, header, render, className }`
- Optional row click handler
- Sticky header with border

