import type { WeeklyActivity } from "@/types/repository";

interface ActivityChartProps {
  activity: WeeklyActivity[];
  weeks?: number;
}

export function ActivityChart({ activity, weeks = 16 }: ActivityChartProps) {
  const recent = activity.slice(-weeks);
  if (recent.length === 0) {
    return (
      <div className="rounded-xl border border-border bg-surface p-6 text-center text-sm text-muted">
        No commit activity data available
      </div>
    );
  }

  const maxTotal = Math.max(...recent.map((w) => w.total), 1);
  const barWidth = 100 / recent.length;
  const chartHeight = 120;

  return (
    <div className="rounded-xl border border-border bg-surface p-5">
      <h3 className="mb-4 text-xs font-medium uppercase tracking-wider text-muted">
        Commit Activity
      </h3>
      <svg
        viewBox={`0 0 ${recent.length * 20} ${chartHeight}`}
        className="w-full"
        preserveAspectRatio="none"
      >
        {recent.map((week, i) => {
          const height = (week.total / maxTotal) * (chartHeight - 10);
          const x = i * 20 + 2;
          const y = chartHeight - height;
          return (
            <g key={week.week}>
              <rect
                x={x}
                y={y}
                width={16}
                height={height}
                rx={3}
                className="fill-accent/60 hover:fill-accent transition-colors"
              />
              <title>
                {new Date(week.week * 1000).toLocaleDateString()}: {week.total} commits
              </title>
            </g>
          );
        })}
      </svg>
    </div>
  );
}

