"use client";

import { use } from "react";
import { useRepoDetail } from "@/hooks/use-repo-detail";
import { useContributors } from "@/hooks/use-contributors";
import { useActivity } from "@/hooks/use-activity";
import { usePulls } from "@/hooks/use-pulls";
import { useIssues } from "@/hooks/use-issues";
import { Skeleton } from "@/components/ui/skeleton";
import { RepoSidebarInfo } from "@/components/repo/repo-sidebar-info";
import { RepoStatsBar } from "@/components/repo/repo-stats-bar";
import { ActivityChart } from "@/components/repo/activity-chart";
import { OpenPRsList } from "@/components/repo/open-prs-list";
import { OpenIssuesList } from "@/components/repo/open-issues-list";

export default function OverviewPage({
  params,
}: {
  params: Promise<{ owner: string; repo: string }>;
}) {
  const { owner, repo } = use(params);
  const { repo: repoDetail, isLoading: repoLoading } = useRepoDetail(owner, repo);
  const { contributors } = useContributors(owner, repo);
  const { activity, isLoading: activityLoading } = useActivity(owner, repo);
  const { pulls } = usePulls(owner, repo, "open");
  const { issues } = useIssues(owner, repo, "open");

  if (repoLoading) {
    return (
      <div className="space-y-4">
        <div className="grid grid-cols-5 gap-3">
          {Array.from({ length: 5 }).map((_, i) => (
            <Skeleton key={i} className="h-20" />
          ))}
        </div>
        <Skeleton className="h-48" />
      </div>
    );
  }

  if (!repoDetail) {
    return (
      <div className="rounded-xl border border-border bg-surface p-8 text-center text-sm text-muted">
        Failed to load repository details
      </div>
    );
  }

  return (
    <div className="flex gap-6">
      {/* Left sidebar */}
      <aside className="hidden w-72 shrink-0 lg:block">
        <RepoSidebarInfo repo={repoDetail} contributors={contributors} />
      </aside>

      {/* Main content */}
      <div className="min-w-0 flex-1 space-y-6">
        {/* Stats bar */}
        <RepoStatsBar
          repo={repoDetail}
          openPRs={pulls?.length}
          openIssues={issues?.length}
        />

        {/* Activity chart */}
        {activityLoading ? (
          <Skeleton className="h-48" />
        ) : (
          activity && <ActivityChart activity={activity} />
        )}

        {/* Three-column grid: PRs + Issues */}
        <div className="grid gap-6 md:grid-cols-2">
          <div className="rounded-xl border border-border bg-surface p-4">
            <h3 className="mb-3 text-xs font-medium uppercase tracking-wider text-muted">
              Open Pull Requests
            </h3>
            {pulls ? (
              <OpenPRsList pulls={pulls} owner={owner} repo={repo} />
            ) : (
              <Skeleton className="h-32" />
            )}
          </div>
          <div className="rounded-xl border border-border bg-surface p-4">
            <h3 className="mb-3 text-xs font-medium uppercase tracking-wider text-muted">
              Open Issues
            </h3>
            {issues ? (
              <OpenIssuesList issues={issues} owner={owner} repo={repo} />
            ) : (
              <Skeleton className="h-32" />
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

