"use client";

import { useEffect, useState } from "react";
import type { FileContent } from "@/types/repository";

interface FileViewerProps {
  file: FileContent;
}

function getLanguageFromFilename(filename: string): string {
  const ext = filename.split(".").pop()?.toLowerCase() ?? "";
  const map: Record<string, string> = {
    ts: "typescript",
    tsx: "tsx",
    js: "javascript",
    jsx: "jsx",
    py: "python",
    rb: "ruby",
    rs: "rust",
    go: "go",
    java: "java",
    kt: "kotlin",
    swift: "swift",
    c: "c",
    cpp: "cpp",
    h: "c",
    hpp: "cpp",
    cs: "csharp",
    php: "php",
    html: "html",
    css: "css",
    scss: "scss",
    less: "less",
    json: "json",
    yaml: "yaml",
    yml: "yaml",
    toml: "toml",
    xml: "xml",
    md: "markdown",
    mdx: "mdx",
    sql: "sql",
    sh: "bash",
    bash: "bash",
    zsh: "bash",
    dockerfile: "dockerfile",
    makefile: "makefile",
    vue: "vue",
    svelte: "svelte",
    graphql: "graphql",
    gql: "graphql",
  };
  return map[ext] || "text";
}

export function FileViewer({ file }: FileViewerProps) {
  const [html, setHtml] = useState<string>("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;

    async function highlight() {
      try {
        const { codeToHtml } = await import("shiki");
        const lang = getLanguageFromFilename(file.name);
        const result = await codeToHtml(file.content, {
          lang,
          theme: "github-dark-default",
        });
        if (!cancelled) setHtml(result);
      } catch {
        // Fallback: render as plain text
        if (!cancelled) {
          setHtml("");
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    highlight();
    return () => { cancelled = true; };
  }, [file.content, file.name]);

  const lines = file.content.split("\n");

  return (
    <div className="rounded-xl border border-border bg-surface overflow-hidden">
      {/* File header */}
      <div className="flex items-center justify-between border-b border-border bg-surface-light px-4 py-2">
        <span className="text-sm text-foreground font-mono">{file.name}</span>
        <span className="text-xs text-muted">
          {lines.length} lines &middot; {formatSize(file.size)}
        </span>
      </div>

      {/* Code content */}
      <div className="overflow-x-auto">
        {loading ? (
          <pre className="p-4 text-sm font-mono text-foreground">
            <code>{file.content}</code>
          </pre>
        ) : html ? (
          <div
            className="shiki-container text-sm [&_pre]:!bg-transparent [&_pre]:p-4 [&_code]:!text-sm"
            dangerouslySetInnerHTML={{ __html: html }}
          />
        ) : (
          <pre className="p-4 text-sm font-mono text-foreground">
            <code>{file.content}</code>
          </pre>
        )}
      </div>
    </div>
  );
}

function formatSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

