import Link from "next/link";
import { Avatar } from "@/components/ui/avatar";
import { formatDistanceToNow, format, isSameDay } from "date-fns";
import type { CommitSummary } from "@/types/repository";

interface CommitListProps {
  commits: CommitSummary[];
  owner: string;
  repo: string;
}

export function CommitList({ commits, owner, repo }: CommitListProps) {
  // Group commits by date
  const groups: { date: Date; commits: CommitSummary[] }[] = [];
  for (const commit of commits) {
    const date = new Date(commit.date);
    const existing = groups.find((g) => isSameDay(g.date, date));
    if (existing) {
      existing.commits.push(commit);
    } else {
      groups.push({ date, commits: [commit] });
    }
  }

  return (
    <div className="space-y-6">
      {groups.map((group) => (
        <div key={group.date.toISOString()}>
          <h3 className="mb-2 text-xs font-medium text-muted">
            {format(group.date, "MMMM d, yyyy")}
          </h3>
          <div className="space-y-1">
            {group.commits.map((commit) => (
              <Link
                key={commit.sha}
                href={`/${owner}/${repo}/commits/${commit.sha}`}
                className="flex items-center gap-3 rounded-lg border border-border bg-surface p-3 transition-colors hover:border-accent/30 hover:bg-surface-light"
              >
                <Avatar
                  src={commit.author?.avatar_url}
                  alt={commit.author?.login ?? "Unknown"}
                  size={28}
                />
                <div className="min-w-0 flex-1">
                  <p className="truncate text-sm text-foreground">
                    {commit.message.split("\n")[0]}
                  </p>
                  <p className="text-xs text-muted">
                    {commit.author?.login ?? "Unknown"} committed{" "}
                    {formatDistanceToNow(new Date(commit.date), { addSuffix: true })}
                  </p>
                </div>
                <span className="shrink-0 font-mono text-xs text-muted">
                  {commit.sha.slice(0, 7)}
                </span>
              </Link>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

